import customtkinter as ctk
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    # IDE-only stubs
    from nl_sdk_registers import ui_registry as uireg, redactable_data_registry as rdr
    from nl_sdk import PluginContext
else:
    # Real core injection
    try:
        from Registers import ui_registry as uireg, redactable_data_registry as rdr
    except ImportError:
        uireg, rdr = None, None

class MyPlugin:
    def __init__(self, ctx: 'PluginContext'):
        self.ctx = ctx

    def on_enable(self):
        if rdr:
            rdr.bind(f'{self.ctx.id}_active', True)
        self.ctx.log('Plugin initialized!')

{
    "id": "my_unique_plugin",
    "name": "Example Tool",
    "version": "1.0.0",
    "main_class": "PluginMain"
}

class PluginMain:
    def __init__(self, ctx):
        # ctx is an instance of PluginContext
        self.ctx = ctx 

    def on_enable(self):
        self.ctx.log("Initializing UI...")
        # Mount a button to the main frame via UIRegistry anchor
        self.ctx.mount_ui(
            anchor_name="MainWindowPluginFrame", 
            widget_cls=ctk.CTkButton, 
            text="Hello Core!", 
            command=lambda: self.ctx.log("Button clicked!")
        )
